    @Test
    @DisplayName("clone() returns a deep copy with independent outputSettings, parser, and child nodes")
    public void test_TC01() {
        // GIVEN a shell document with a child html element (ensures B1->childNodes branch executed)
        Document original = Document.createShell("http://example.com");
        // WHEN clone is called to perform deep copy (invokes B2->B3 branch of clone override)
        Document copy = original.clone();
        // THEN assert copy is a new instance
        assertNotSame(original, copy, "Cloned document should not be same instance as original");
        // AND outputSettings should be independent instances (deep clone)
        assertNotSame(original.outputSettings(), copy.outputSettings(),
                "OutputSettings should be deep-copied, not same instance");
        // AND parser should be a cloned instance, not same as original.parser
        assertNotSame(original.parser(), copy.parser(),
                "Parser should be deep-copied via clone(), not same instance");
        // AND child nodes list sizes should be equal
        List<?> originalChildren = original.childNodes();
        List<?> copyChildren = copy.childNodes();
        assertEquals(originalChildren.size(), copyChildren.size(),
                "Child nodes count should be equal after clone");
