        for (int i = 0; i < originalChildren.size(); i++) {
            Object origNode = originalChildren.get(i);
            Object copyNode = copyChildren.get(i);
            assertNotSame(origNode, copyNode, "Each child node should be a distinct instance");
            // Compare HTML content to ensure same content
            assertEquals(origNode.toString(), copyNode.toString(),
                    "Child node content should be equal after deep clone");
        }
    }

